class Graph:
    def __init__(self):
        self.adj_list = {}

    def add_vertex(self, vertex):
        if vertex not in self.adj_list:
            self.adj_list[vertex] = []
            return True
        return False

    def add_edge(self, v1, v2, directed=False):
        if v1 in self.adj_list and v2 in self.adj_list:
            if v2 not in self.adj_list[v1]:
                self.adj_list[v1].append(v2)
            if not directed:
                if v1 not in self.adj_list[v2]:
                    self.adj_list[v2].append(v1)
            return True
        return False

    def remove_edge(self, v1, v2, directed=False):
        if v1 in self.adj_list and v2 in self.adj_list:
            try:
                self.adj_list[v1].remove(v2)
                if not directed:
                    self.adj_list[v2].remove(v1)
                return True
            except ValueError:
                pass # Edge not found
        return False

    def remove_vertex(self, vertex):
        if vertex in self.adj_list:
            for other_vertex in list(self.adj_list[vertex]): # Iterate over a copy to allow modification
                self.remove_edge(vertex, other_vertex) # Remove outgoing edges
            # Now remove incoming edges from other vertices
            for v_key in self.adj_list:
                if vertex in self.adj_list[v_key]:
                    self.adj_list[v_key].remove(vertex)
            del self.adj_list[vertex]
            return True
        return False

    def print_graph(self):
        for vertex in self.adj_list:
            print(f"{vertex}: {self.adj_list[vertex]}")

if __name__ == '__main__':
    my_graph = Graph()
    my_graph.add_vertex("A")
    my_graph.add_vertex("B")
    my_graph.add_vertex("C")
    my_graph.add_vertex("D")
    my_graph.add_vertex("E")

    my_graph.add_edge("A", "B")
    my_graph.add_edge("A", "C")
    my_graph.add_edge("B", "D")
    my_graph.add_edge("C", "D")
    my_graph.add_edge("D", "E")

    print("Undirected Graph:")
    my_graph.print_graph()

    print("\nRemoving edge (A, C):")
    my_graph.remove_edge("A", "C")
    my_graph.print_graph()

    print("\nRemoving vertex D:")
    my_graph.remove_vertex("D")
    my_graph.print_graph()

    print("\nDirected Graph Example:")
    directed_graph = Graph()
    directed_graph.add_vertex("X")
    directed_graph.add_vertex("Y")
    directed_graph.add_vertex("Z")
    directed_graph.add_edge("X", "Y", directed=True)
    directed_graph.add_edge("Y", "Z", directed=True)
    directed_graph.add_edge("Z", "X", directed=True)
    directed_graph.print_graph()
